INSERT INTO `jobs` (`id`, `external_dataset_id`, `user_id`, `title`, `company`, `location`, `work_mode`, `employment_type`, `seniority`, `category`, `ml_predicted_category`, `ml_model`, `ml_confidence`, `ml_probabilities_json`, `salary_range`, `technologies_json`, `posted_at`, `source_type`, `source_note`, `difficulty_score`, `description`, `match_score`, `status`, `applied_at`, `start_period`, `created_at`, `updated_at`, `experience_min`, `experience_label`, `degree_level`, `degree_label`, `meets_experience_requirement`, `meets_degree_requirement`) VALUES
(104, 'CJ-004', 1, 'Business Intelligence Specialist', 'DeLonghi Romania', 'Cluj-Napoca / Remote Romania', 'ONSITE', 'FULL_TIME', 'MID', 'BI', NULL, NULL, NULL, NULL, NULL, '[\"Power BI\", \"SQL Server\", \"Power Query\"]', '2026-04-09', 'REALISTIC_SYNTHETIC', 'Rol realist-sintetic construit pentru demo academic SkillTrack, inspirat din piața IT/business din Cluj și din tipologiile publice de joburi.', 65, 'DeLonghi Romania caută un/o Business Intelligence Specialist pentru echipele din Cluj-Napoca, cu activitate în regim onsite. Rolul presupune colaborare cu stakeholderi tehnici și business pentru livrarea de soluții digitale, rapoarte sau funcționalități software relevante. Candidatul va lucra cu Power BI, SQL Server, Power Query și va folosi în mod constant competențe precum Power BI, SQL, ETL, Data Modeling, Dashboard Design. Responsabilitățile includ analiză de cerințe, documentare, implementare sau testare, în funcție de specificul rolului. Sunt importante comunicarea clară, atenția la detalii și capacitatea de a transforma informațiile operaționale în rezultate acționabile. Experiența cu instrumente moderne, versionare, lucru Agile și colaborare cross-functională reprezintă un avantaj. Poziția este potrivită pentru nivel mid și contribuie direct la proiecte locale sau internaționale.', 67, 'OFERTA', NULL, NULL, '2026-05-17 22:08:32', '2026-05-20 08:16:40', 2, '2–5 ani experiență', NULL, NULL, NULL, NULL),
